import { Component, Input, Output, EventEmitter } from '@angular/core';
import { TextStatsService } from '../../services/text-stats.service';
import { Observable } from 'rxjs';

@Component({
  selector: 'app-formatters',
  templateUrl: './formatters.component.html',
  styleUrls: ['./formatters.component.css']
})
export class FormattersComponent {

  @Input() textColor: string = '#222222';

  // Live stats — initialized inline (fixes strict mode red lines)
  wordCount$: Observable<number> = this.statsService.wordCount$;
  charCount$: Observable<number> = this.statsService.charCount$;

  constructor(private statsService: TextStatsService) {}

  @Output() clearAll           = new EventEmitter<void>();
  @Output() removeExtraSpaces  = new EventEmitter<void>();
  @Output() reverseSentence    = new EventEmitter<void>();
  @Output() removeSpecialChars = new EventEmitter<void>();
  @Output() capitalizeWords    = new EventEmitter<void>();
  @Output() toggleBold         = new EventEmitter<void>();
  @Output() toggleItalic       = new EventEmitter<void>();
  @Output() toggleUnderline    = new EventEmitter<void>();
  @Output() colorChange        = new EventEmitter<string>();
  @Output() removeStyling      = new EventEmitter<void>();
  @Output() increaseFontSize   = new EventEmitter<void>();
  @Output() decreaseFontSize   = new EventEmitter<void>();

  onColorInput(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.colorChange.emit(input.value);
  }
}
<div class="right-panel">

  <!-- ── STATS BLOCK ── -->
  <div class="stats-block">
    <div class="stat-row">
      <span class="stat-key">Word Count: </span>
      <span class="stat-val">{{ wordCount$ | async }} Words</span>
    </div>
    <div class="stat-row">
      <span class="stat-key">Char Count: </span>
      <span class="stat-val">{{ charCount$ | async }} Chars</span>
    </div>
  </div>

  <!-- ── OPERATIONS BLOCK ── -->
  <div class="ops-block">

    <!-- Row 1 -->
    <div class="btn-row">
      <button class="op-btn" (click)="clearAll.emit()">Clear All</button>
      <button class="op-btn" (click)="removeExtraSpaces.emit()">White-space Remove</button>
    </div>

    <!-- Row 2 -->
    <div class="btn-row">
      <button class="op-btn" (click)="reverseSentence.emit()">Reverse All</button>
      <button class="op-btn" (click)="removeSpecialChars.emit()">Remove Special Char</button>
    </div>

    <!-- Row 3 -->
    <div class="btn-row">
      <button class="op-btn" (click)="removeStyling.emit()">Remove styling</button>
      <button class="op-btn" (click)="capitalizeWords.emit()">Capitalize Word</button>
    </div>

    <!-- ── STYLING ROW — matches Image 1 exactly ── -->
    <div class="style-row">

      <!-- B -->
      <button class="sty-btn" (click)="toggleBold.emit()" title="Bold">
        <strong>B</strong>
      </button>

      <!-- I -->
      <button class="sty-btn italic-btn" (click)="toggleItalic.emit()" title="Italic">
        <em>I</em>
      </button>

      <!-- U with underline -->
      <button class="sty-btn" (click)="toggleUnderline.emit()" title="Underline">
        <span class="u-letter">U</span>
      </button>

      <!-- Rainbow color picker circle — image 1 shows rainbow/spectrum circle -->
      <label class="sty-btn color-label" title="Text Color">
        <span class="rainbow-circle"></span>
        <input
          type="color"
          class="hidden-color"
          [value]="textColor"
          (input)="onColorInput($event)"
          aria-label="Text color">
      </label>

      <!-- + font size -->
      <button class="sty-btn size-btn" (click)="increaseFontSize.emit()" title="Increase size">+</button>

      <!-- − font size -->
      <button class="sty-btn size-btn" (click)="decreaseFontSize.emit()" title="Decrease size">−</button>

    </div>
  </div>

</div>
